var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"쓰러져 있는 앤을 발견했을 때.","JPN":"倒れているアンを見つけた時。","ENG":"When I saw Ann collapsed on the floor.","TWN":"我們發現安妮暈倒在地上。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"우리는 침식체가 되지 않은 앤을 보고 안도할 수밖에 없었다.","JPN":"私たちは侵食体になっていないアンを見て安堵した。","ENG":"We were relieved to see that Ann didn't turn into a C.O.","TWN":"當我們看到安妮沒有成為侵蝕體時，放下了懸著的心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 의식을 회복한 앤은 이미…….","JPN":"しかし、意識を取り戻したアンは……","ENG":"But when she regained consciousness, she...","TWN":"但是恢復意識的安妮已經……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"다른 사람이 되어있었다.","JPN":"別人になっていた。","ENG":"was a totally different person.","TWN":"變成了另外一個人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"얘들아! 어서 뛰어!","JPN":"みんな！　早く走って！","ENG":"Guys! Run!","TWN":"大家快跑！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L8_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"보육원으로 가면 안 돼! 거긴 이미 침식체들 천지야!","JPN":"保育園に行っちゃダメ！　そこはもう侵食体だらけだよ！","ENG":"Don’t head toward the orphanage! It’s already packed with C.O.s there!","TWN":"不可以去育幼院！那裡全都是侵蝕體！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"……어? 어?","JPN":"……え？　え？","ENG":"H-huh…?","TWN":"……啊？啊？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"얘! 너 거기서 뭐 해! 가면 안 된다니까!","JPN":"ちょっと！　そこで何してるの！　行っちゃダメだって！","ENG":"Hey! What do you think you’re doing there? You can’t go that way!","TWN":"喂！你站在那幹什麼呢！不可以過去！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"잠깐만요, 수녀님! 제가 다시 데려올게요!","JPN":"待って、シスター！　私が連れ戻してきます！","ENG":"It'll only take a second, ma'am! I'll bring her right back!","TWN":"請等一下，修女！我去把她帶回來！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤! 어디가는 거야……!!","JPN":"アン！　どこに行くの……！！","ENG":"Ann! Where are you going...?!","TWN":"安妮！你去哪裡啊……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"정신 차려! 보육원으로 가면 안 돼!","JPN":"しっかりして！　保育園に行っちゃダメ！！","ENG":"Snap out of it! You can't go back to the orphanage!","TWN":"打起精神啊！別再往育幼院跑了！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ff3636>이거 놔!</color>","JPN":"<color=#ff3636>離して！</color>","ENG":"<color=#ff3636>Let go of me!</color>","TWN":"<color=#ff3636>放開我！</color>"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ff3636>그 역겨운 버넷…… 감히 또 내 일을 망치려 들어!?</color>","JPN":"<color=#ff3636>憎たらしいバーネット……また私の邪魔をするつもりね！？</color>","ENG":"<color=#ff3636>That filthy Burnett... How dare he try to ruin my plans again!</color>","TWN":"<color=#ff3636>那個噁心的伯內特……竟敢破壞我的好事？！</color>"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ff3636>이번에야 말로 반드시 죽여주지.</color>","JPN":"<color=#ff3636>今度こそ必ず殺してやるわ！</color>","ENG":"<color=#ff3636>I'll make sure to kill him for good this time.</color>","TWN":"<color=#ff3636>這次我一定要殺了你。</color>"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"너, 누구야?","JPN":"あなた、誰？","ENG":"Who are you?","TWN":"你，是誰？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤을 어떻게 한 거야! 앤을 돌려줘!","JPN":"アンに何をしたの？　アンを返して！","ENG":"What did you do to Ann?! Bring Ann back!","TWN":"你把安妮怎麼樣了！把安妮還給我！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ff3636>어린 년이 건방지게 어딜!</color>","JPN":"<color=#ff3636>小娘の分際で生意気な！</color>","ENG":"<color=#ff3636>You insolent girl! How dare you talk to me like that?!</color>","TWN":"<color=#ff3636>小丫頭，竟敢碰我！</color>"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"……꺅!","JPN":"……きゃっ！","ENG":"...Kyaaa!","TWN":"……啊！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤을…… 앤을 구해야 해!","JPN":"アンを……アンを助けないと！","ENG":"I... I need to save Ann!","TWN":"安妮……我要救安妮！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤이 없으면, 나는…….","JPN":"アンがいないと、私は……","ENG":"Without her, I'm...","TWN":"如果沒有安妮，那我……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"왜 그러지?","JPN":"どうした？","ENG":"What's wrong?","TWN":"怎麼了？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇게 자신만만 하더니, 결국 잔해 따위에 의존하는 꼴인가?","JPN":"あんなに大口叩いておいて、結局は残骸などに頼るのか？","ENG":"You were so confident, but now you've resorted to relying on the Remains?","TWN":"你不是很有自信嗎？但到頭來還是得依靠這些殘骸？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"이딴 게 나한테 안 통한다는 건 네놈도 이미 알고 있을 텐데?","JPN":"こんなもの俺には通じないってことぐらい貴様もわかってるだろ？","ENG":"I'm sure you already know that these things won't even put a scratch on me.","TWN":"你這傢伙應該也知道，這種東西根本對我行不通吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L48_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"아니면 벌써 노망이라도 난 건가?","JPN":"それとも、すでにボケたのか？","ENG":"Or have you already gone mad?","TWN":"還是說，你已經老糊塗了？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"역시 대단하군.","JPN":"さすがだ。","ENG":"I'll admit, you're strong.","TWN":"果然很厲害。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"하지만 평소보다 조급한 것처럼 보이는데…….","JPN":"だが、いつもより焦ってるように見えるが……","ENG":"But you seem more impatient than usual...","TWN":"但是你看起來比平時焦慮多了……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"단지 내 기분 탓일까, 버넷?","JPN":"それは気のせいかね、バーネット？","ENG":"Or is it just my imagination, Burnett?","TWN":"這只是我的錯覺嗎，伯內特？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"허튼 소리는 집어 치워!","JPN":"戯言を聞いてやる暇はない！","ENG":"Enough with your nonsense!","TWN":"少說廢話！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"……크으윽!","JPN":"……くううっ！","ENG":"...Ugh!","TWN":"……咳呃！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"끝이다, 제임스.","JPN":"終わりだ、ジェームス。","ENG":"It's over, James.","TWN":"結束了，詹姆斯。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"이제 두 번 다시 이딴 짓을 벌일 수 없게 만들어 주지.","JPN":"二度とこんなことはできないようにしてやる。","ENG":"I'll make sure that you never do something like this again.","TWN":"我絕不會讓你再犯下這種事。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"후후, 과연 그럴까?","JPN":"ふふ、それはどうかね？","ENG":"Haha, is that so?","TWN":"呵呵，果真如此嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何だと？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"자네도 알고 있겠지만, 잔해는 클리파 허수 에너지로 생성된 침식체지.","JPN":"君も知っての通り、残骸はクリファ虚数エネルギーで生成された侵食体。","ENG":"I'm sure you're aware, but the Remains are C.O.s made from Qlipha Imaginary Energy.","TWN":"你也知道，殘骸是因逆卡巴拉虛數能量產生的侵蝕體。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그리고 이 지팡이는 효율은 좋지 않지만, 잔해를 폭주시켜 폭발을 일으킬 수 있어.","JPN":"この杖は効率は悪いが、残骸を暴走させて爆発させることができる。","ENG":"And, although this Staff is not as efficient, it has the ability to cause the Remains to explode.","TWN":"這根拐杖雖然效率不高，但能使殘骸暴走，引發爆炸。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"마치 도화선에 불을 붙이듯 말이야.","JPN":"導火線に火をつけるようにね。","ENG":"Much like setting fire to a fuse, that is.","TWN":"就像點燃導火線一樣。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이렇게 잔해가 응집된 공간이라면 연쇄적인 폭발을 일으키겠지.","JPN":"こんなにも残骸が集まっている空間なら、連鎖的な爆発が起こせるだろう。","ENG":"And with so many of the Remains in this confined space, it will cause a series of explosions.","TWN":"如果是殘骸聚集的空間，還會引發連鎖爆炸。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그럼 어떻게 될지…… 궁금하지 않나?","JPN":"それを実行したらどうなるか……見たいと思わないかい？","ENG":"And... aren't you curious about what would happen next?","TWN":"那後果會怎麼樣……你難道不好奇嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"부디 자네들이 구한 아이들이 이곳에서 최대한 멀리 떨어졌길 바라지.","JPN":"君たちが助けた子どもたちが、ここから遠く離れていることを祈るよ。","ENG":"I hope that the children you saved are far away from here as possible.","TWN":"但願你們救出來的孩子，已經離這裡很遠了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"폭발에 휘말리지 않도록 말이야.","JPN":"爆発に巻き込まれないように、ね。","ENG":"So they don't get caught in the explosion.","TWN":"以免被捲入爆炸。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"……같잖군.","JPN":"……くだらないな。","ENG":"...Don't be absurd.","TWN":"……可笑。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇게 추하게 주저리주저리 떠들어대면서 시간을 버는 꼴을 보면.","JPN":"御託を並べて時間を稼いでいるのを見る限り……","ENG":"Seeing how you're trying to buy time with meaningless chatter,","TWN":"看你這麼嘮嘮叨叨沒完，只為爭取時間的樣子……"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L47_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"즉시 발동할 수 있는 아티팩트는 아니겠지?","JPN":"すぐに発動できるアーティファクトではないだろう。","ENG":"that Artifact doesn't activate immediately, eh?","TWN":"應該是不能立即啟動的人造神器吧？"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼, 그 사이에 이곳에 있는 잔해들을 전부 쓸어주지.","JPN":"それなら、その前にこの残骸を残部蹴散らしてやるまでだ。","ENG":"Then, I'll just have to sweep the Remains before then.","TWN":"那麼，我就趁這個機會把這裡的殘骸全部清除掉。"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L1_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"네놈을 처분하는 건 그 다음이야.","JPN":"貴様の処分はその後だ。","ENG":"I'll dispose of you after that.","TWN":"之後，我再處置你。"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그래? 그럼 어디 열심히 분발해 보게나.","JPN":"そうかい？　なら、せいぜい頑張ってみるがいい。","ENG":"Oh, really? I'd like to see you try.","TWN":"是嗎？那請你好好加油。"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"사, 살려주세요! 요원님!","JPN":"た、助けてください！　エージェントさん！","ENG":"Mr. Agent! H-help me!","TWN":"救，救命啊！先生！"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"너는……?","JPN":"お前は……？","ENG":"Aren't you...?","TWN":"你是……？"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"네가 왜 여기 있지? 다른 아이들은 어떻게 됐나.","JPN":"お前はなぜここにいる？　他の子どもたちは？","ENG":"Why are you here? What happened to the others?","TWN":"你怎麼在這裡？其他孩子怎麼樣了？"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"대피하던 중에 침식체들의 습격을 받았어요!","JPN":"逃げてる途中、侵食体に襲われました！","ENG":"We were all attacked by C.O.s while evacuating!","TWN":"我們在逃跑的時候遭到了侵蝕體的攻擊！"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"다른 애들은 벌써…….","JPN":"他のみんなはもう……","ENG":"They're all...","TWN":"其他的孩子早已經……"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"거짓말이에요!","JPN":"嘘です！","ENG":"She's lying!","TWN":"是騙人的！"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤은 지금 제정신이 아니에요! 뭔가 앤을 조종하고 있어요!","JPN":"アンは今正気じゃありません！　何かがアンを操っています！","ENG":"That's not Ann! She's being controlled by something!","TWN":"安妮現在精神不正常！有什麼東西在操縱安妮！"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"의식을 조종하고 있다고?","JPN":"意識を操っている？","ENG":"Something's controlling her consciousness?","TWN":"操縱她的意識？"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L16_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"설마!","JPN":"まさか！","ENG":"It can't be!","TWN":"不會吧？！"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ff3636>쳇! 마지막까지 성가시게……!</color>","JPN":"<color=#ff3636>ちっ！　最後まで厄介な……！</color>","ENG":"<color=#ff3636>Tch! It's that brat again...!</color>","TWN":"<color=#ff3636>嘖！到最後都這麼麻煩……！</color>"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ff3636>어쩔 수 없지!</color>","JPN":"<color=#ff3636>仕方ないわね。</color>","ENG":"<color=#ff3636>No matter!</color>","TWN":"<color=#ff3636>沒辦法了！</color>"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"이건 맥크레디의 빙결 능력?","JPN":"これはマクレディーの氷結能力？","ENG":"MacCready's freezing ability?","TWN":"這就是麥克蕾蒂的冰凍能力嗎？"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_THUD"},{"id":"L22_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇다는 말은…….","JPN":"ということは……","ENG":"Then that means...","TWN":"那就是說……"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"후후, 그런건가.","JPN":"ふふ、そういうことか。","ENG":"Haha, is this how this plays out?","TWN":"呵呵，原來如此。"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"예상외의 전개로군. 이건 기회가 되겠어.","JPN":"予想外の展開になってきたね。いいチャンスだ。","ENG":"This is unexpected. It could be an opportunity for me.","TWN":"出乎意料的劇情發展啊，應該是個機會。"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤을 돌려줘! 돌려 달란 말이야!","JPN":"アンを返して！　返してよ！","ENG":"Give Ann back! I said, give her back!","TWN":"把安妮還給我！還給我！"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ff3636>이런 개 같은 계집애가……!</color>","JPN":"<color=#ff3636>このうっとうしい小娘……！</color>","ENG":"<color=#ff3636>Why you little brat...!</color>","TWN":"<color=#ff3636>你這個死丫頭……！</color>"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ff3636>방해하지 마! 어서 놓지 못해!?</color>","JPN":"<color=#ff3636>離せ！　邪魔は許さない！</color>","ENG":"<color=#ff3636>Stop interfering! Let go of me!</color>","TWN":"<color=#ff3636>別妨礙我！還不快放手？！</color>"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"피하기에는 늦었어! 받아 칠 수밖에 없나!","JPN":"爆発を避けるにはもう遅い……！　打ち返すしかないのか……！","ENG":"It's too late! I have to deflect it!","TWN":"已經來不及躲開了！只能硬接嗎！"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만……!","JPN":"だが……！","ENG":"But…!","TWN":"但是……！"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이제 끝이네, 버넷.","JPN":"これで終わりだ、バーネット。","ENG":"It's over, Burnett.","TWN":"結束了，伯內特。"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"수없이 반복되는 그 날의 기억 속에서.","JPN":"何度も繰り返されるあの日の記憶の中で。","ENG":"Within the countlessly repeating memories of that day.","TWN":"在重複了無數次的那段記憶裡。"},"stage":{"bg":"WHITE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"마지막에 떠오르는 것은 폭발에서 우리를 지키려던 요원님의 품과.","JPN":"最後に思い出すのは、爆発から私たちを守ろうとするエージェント様の懐と。","ENG":"The last thing I recall is the agent's arms protecting us from the explosion, and...","TWN":"最後出現的，是在爆炸中守護我們的大人的懷抱……"},"stage":{"bg":"WHITE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"피부로 느껴지는 차가운 쇠사슬.","JPN":"肌に伝わる鎖の冷たさ。","ENG":"the cold chain against my skin.","TWN":"以及那個能切身感受到冰冷的鐵鍊。"},"stage":{"bg":"WHITE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 속이 뒤집어질 것만 같은 멀미감이었다.","JPN":"そして吐きそうになる感覚だった。","ENG":"There was also this queasiness, enough to make one sick to the stomach.","TWN":"還有，一種眩暈的感覺。"},"stage":{"bg":"WHITE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 다시금 눈을 떴을 때, 내가 마주하는 세계는.","JPN":"やがて気を取り戻した私の目の前に広がる世界は……","ENG":"After, when I opened my eyes, the world I saw was...","TWN":"當我再次睜開眼睛時，面對的世界……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"언제나 끔찍한 풍경의 이곳.","JPN":"終わりのない惨状が広がるこの場所。","ENG":"this horrible landscape.","TWN":"總是慘不忍睹的這裡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"이브, 정신이 들어!?","JPN":"イヴ、大丈夫！？","ENG":"Eve, are you awake?!","TWN":"伊芙，你醒了？！"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"또 그 이상한 꿈을 꾼 거야?","JPN":"またあの変な夢をみたの？","ENG":"Did you have that weird dream again?","TWN":"又做了那個奇怪的夢嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"에휴, 정신감응이라고 했던가? 너도 참 성가시겠다, 그거.","JPN":"はあ、テレパシーだっけ？　あなたも大変だね。","ENG":"Ugh, telepathy, was it? Seems like a real hassle.","TWN":"精神感應是吧？那個能力也太煩人了吧。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"기분 나쁘니까, 앤의 목소리로 장난치지 마세요.","JPN":"アンの声でふざけるのはやめてください。気分が悪いので。","ENG":"It's annoying, so stop joking around using Ann's voice.","TWN":"不要用安妮的聲音開玩笑，這讓我很不高興。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ffd34c>안나 맥크레디</color>.","JPN":"<color=#ffd34c>アンナ・マクレディー</color>。","ENG":"<color=#ffd34c>Anna MacCready</color>.","TWN":"<color=#ffd34c>安娜·麥克蕾蒂</color>。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"크큭…… 꼬맹이 주제에 귀염성이 없네.","JPN":"くくっ……小娘のくせに、可愛げがないわね。","ENG":"Keke... For a kid, you don't act cute at all.","TWN":"呵呵……小丫頭，你可真不討人喜歡。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그런 말하는 나도 지금은 꼬맹이 신세지만 말이야.","JPN":"そういう私も今は小娘の体に入っているけどね。","ENG":"But then again, I'm also a kid now.","TWN":"雖說，說這種話的我，現在也是小丫頭。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"뻔뻔한 아줌마네요. 앤에게 들러붙어 사는 주제에.","JPN":"ずうずうしいおばさんですね。アンに取り憑いているくせに。","ENG":"You're a shameless old woman who leeched onto Ann.","TWN":"真是個厚臉皮的阿姨，不過就是依附安妮生存而已。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"후후, 나한테 아줌마라니…….","JPN":"ふふ、私に向かっておばさんって……","ENG":"Heh heh, did you just call me an old woman...?","TWN":"呵呵，竟然說我是阿姨……"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"너, 네가 몇 살인 줄은 알고 그런 말을 하는 거야?","JPN":"お前、私が何歳だと思っているの？","ENG":"Hey, do you even know how old you are?","TWN":"你，知道我多大趕說那種話？"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"나름 운이 좋았다고 생각하고 있어.","JPN":"運が良かったんだと思うわ。","ENG":"I consider myself lucky.","TWN":"我覺得自己還算幸運。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"고고학부장이 나랑 한 약속을 어기지 않아서 말이야.","JPN":"考古学部長が私との約束を破らなかったからね。","ENG":"That the Dean of Archeology didn't break the promise he made to me.","TWN":"因為考古學教授沒有違背與我的承諾。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"로젠탈에서 주입하고 있는 파편에는 사실, 내 사념이 깃들어 있었거든.","JPN":"実はローゼンタールで注入していた破片には私の思念が宿っていたの。","ENG":"The Fragments they injected the children with at Rosenthal actually contained my consciousness.","TWN":"在羅森泰注入的碎片中，其實寄宿著我的意念。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"에델, 그 망할 년 때문에 이 몸에 깃든 것이 내 <color=#ffd34c>마지막 사념</color>이 될 줄 몰랐지만 말이야.","JPN":"エデル、あのクソ女のせいでこの肉体に宿したのが私の<color=#ffd34c>最後の思念</color>になるとは思わなかったけどね。","ENG":"But because of that bitch Edel, I never imagined that the consciousness to pervade this body would be <color=#ffd34c>my last</color>.","TWN":"只是沒想到會因為艾瑟兒那個臭女人，這副身軀蘊含的會是我<color=#ffd34c>最後的意念</color>。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"앤이라고 했나?","JPN":"アンって言ったかしら？","ENG":"Her name was Ann?","TWN":"是叫安妮嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"다행히도 이 아이는 그릇으로서 어느 정도 소질을 갖고 있었어.","JPN":"幸いこの子は器としてある程度の素質を持っていたわ。","ENG":"I was fortunate enough that she was a compatible vessel.","TWN":"幸好這孩子，還挺有作為器皿的天賦。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그래서 이렇게 나를 담고서도…… 넘치지 않고 형체를 유지할 수 있던 거지.","JPN":"だから私を宿しても……形を変えず維持できているわけ。","ENG":"That's how, even after containing me... she's still able to maintain her form.","TWN":"即使這樣裝下我……也不會溢出來，還可以維持形體。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"뭐, 이 아이의 인격과 내 기억이 뒤섞여 버려 지금 난 온전한 <color=#ffd34c>맥크레디</color>라고는 할 수 없지만.","JPN":"まあ、この子の人格と私の記憶が混ざりあったせいで、今の私は完全な<color=#ffd34c>マクレディー</color>とは言えないけど。","ENG":"Well, I can't be considered the complete <color=#ffd34c>MacCready</color> because her personality and my memories have been mixed together.","TWN":"雖說這個孩子的人格和我的記憶混雜在一起，所以不能說現在的我是完整的<color=#ffd34c>麥克蕾蒂</color>。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그리고 그릇의 자질로 따지면, 넌 훨씬 격이 높아. 이브.","JPN":"それに、器の素質だけでいうなら、お前の方が格上よ、イヴ。","ENG":"And talking about the quality of a vessel, she's incomparable to you, Eve.","TWN":"其實論器皿的資質，你的檔次要高上很多，伊芙。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"자, 고개를 돌려줄 테니 네 눈으로 직접 봐.","JPN":"さあ、頭を動かしてやるから自分の目で確かめてごらん。","ENG":"Now, I'll tilt your head so you can see for yourself.","TWN":"來，我幫你把頭轉過去，你親眼看看吧。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"시, 싫어……!","JPN":"い、嫌よ……！","ENG":"N-no...!","TWN":"不，不要……！"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"네 안에 있던 작은 파편이 이렇게나 커졌단다.","JPN":"お前の中の小さな破片が、こんなにも大きくなったのよ。","ENG":"The little Fragment that was inside you has grown to be this big.","TWN":"你心裡的小碎片已經變得這麼大了。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"지금, 이 순간에도 탐욕스럽게 뿌리를 내려 세계 하나를 통째로 탐식하려 하지.","JPN":"今この瞬間も貪欲に根を張り、世界を丸ごと貪り喰おうとしている。","ENG":"Even now, its greedy roots are digging deep into the ground, trying to consume the world whole.","TWN":"此時此刻，你還在貪婪地紮根，試圖蠶食整個世界。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_BONE_CRACK"},{"id":"L44_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"아니야……!","JPN":"違う……！","ENG":"No...!","TWN":"不是的……！"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그런데 너는 자아를 잃기는커녕 멀쩡하잖아!?","JPN":"なのにお前はまったく自我を失っていない！","ENG":"But still, look at you! You're fine and haven't even lost your consciousness!","TWN":"可你不僅沒有失去自我，反而非常清醒！"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"물론, 몸 전체가 파편에 뒤얽혀 꼼짝도 할 수 없게 된 건 안타깝지만.","JPN":"もちろん、全身が破片に絡まって身動きも取れなくなってしまったのは残念だけど。","ENG":"Of course, it's a shame that your entire body is tangled with the Fragment, making you unable to move.","TWN":"當然，全身都被碎片纏住，無法動彈確實可惜。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"어때? 훌륭하지 않니?","JPN":"どう？　すばらしいと思わない？","ENG":"What do you think? Isn't it magnificent?","TWN":"怎麼樣？你不覺得很棒嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"이 정도 크기의 <color=#ffd34c>파편</color>과 그걸 통제할 수 있는 <color=#ffd34c>육신</color>을 손에 넣는다면…….","JPN":"これほどの大きさの<color=#ffd34c>破片</color>と、それを統制できる<color=#ffd34c>肉体</color>を手に入れたなら……","ENG":"If I could obtain a <color=#ffd34c>Fragment</color> that big with a <color=#ffd34c>body</color> that could control it...","TWN":"如果能得到這麼大的<color=#ffd34c>碎片</color>和能控制它的<color=#ffd34c>肉體</color>……"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그 망할 년들을 숙청해 버리고 내가 다시 학회장으로 복권하는 건 문제도 아니야.","JPN":"あのクソ女どもを粛清し、私が学会長に復権するのは造作もないわ。","ENG":"Then I'll have no problem reinstating myself as the President of the Society and purging those wretched bitches once and for all.","TWN":"那麼肅清那個該死的女人，並重新找回我的學會會長一職，就不是什麼問題了。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"뿔뿔이 조각난 지식의 호수를 하나로 만드는 것도 충분히 가능해.","JPN":"粉々の破片になった知識の湖を一つにすることさえできる。","ENG":"It will also be enough to combine the shattered Lake of Knowledge into one.","TWN":"把零星的知識湖水變成一體也完全有可能。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그러니 그만 포기하고, 그 육신을 나한테 넘기는 게 어때?","JPN":"だからいい加減諦めて、その肉体を私に渡してくれないかしら？","ENG":"So how about you give up and hand over that body to me?","TWN":"所以，你就放棄吧，把你的肉體交給我如何？"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"네 몸은 파편을 감당할 수 있다고 해도, 네 정신은 그게 아니잖아?","JPN":"お前の肉体は破片に耐えられても、精神は違うでしょう？","ENG":"Even if you can physically endure the Fragment within your body, I bet your mentality can't.","TWN":"就算你的身體承受得住碎片，但你的精神卻不是如此吧？"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"내 이름과 명예를 걸고 너희에게 맹세하마.","JPN":"俺の名前と名誉をかけて、お前たちに誓おう。","ENG":"I swear on my name and honor.","TWN":"我以我的名字和榮譽向你們發誓。"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L10_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"버넷 요원님……?","JPN":"バーネット様……？","ENG":"Agent Burnett...?","TWN":"伯內特先生……？"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"아무리 힘들어도, 아무리 오랜 시간이 걸려도 너희를 포기하지 않겠다.","JPN":"どんなに辛い思いをしても、どんなに長い時間がかかっても、俺はお前たちのことを諦めない。","ENG":"No matter how hard, no matter how long, I won't give up on you.","TWN":"無論多累，會花費多少時間，我也不會放棄你們。"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 지금은.","JPN":"だから今は……","ENG":"So for now.","TWN":"所以現在……"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"지금은 조금만 우리를 믿고 기다려 줄 수 있겠니?","JPN":"今は俺たちを信じて、待ってくれないか。","ENG":"Could you trust us and wait a bit?","TWN":"可以相信我，再等我們一會兒嗎？"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"네. 기다릴게요.","JPN":"はい、待ちます。","ENG":"Okay. I'll wait.","TWN":"好的，我會等你的。"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"다른 건 몰라도…… 저, 참는 건 자신 있거든요.","JPN":"なにより……私、耐えることなら自信あるんです。","ENG":"I don't know about anything else, but... I know I'm good at enduring.","TWN":"別的不說……我對忍耐是很有信心的。"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"전 버넷 요원님을 기다릴 거예요.","JPN":"私はバーネット様を待ちます。","ENG":"I'll wait for Agent Burnett.","TWN":"我會等你的，伯內特先生。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"절 포기하지 않겠다고 하셨으니까…… 반드시 와 주실 거예요.","JPN":"諦めないって言ってたから……絶対来てくださるはずです。","ENG":"He said he wouldn't give up on me... So, he'll come to save me, no matter what.","TWN":"你說過不會放棄我……所以你一定會來的對嗎……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"하하핫! 멍청하긴!","JPN":"あははっ！　愚かね！","ENG":"Hah hah hah! Foolish girl!","TWN":"哈哈哈！真是愚蠢！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그로부터 얼마나 시간이 흘렀는데, 다 늙어 빠진 버넷이 살아나 있을 것 같아?","JPN":"あれからどれほどの時間が経っていると思うの？　老いぼれたバーネットが生きていると信じているわけ？","ENG":"It's been ages since he promised that. Do you really believe that old Burnett is still alive?","TWN":"從那以後過了這麼長時間，你還覺得那個老頭還活著嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"잘 들어, 이브.","JPN":"よく聞きなさい、イヴ。","ENG":"Listen carefully, Eve.","TWN":"聽好了，伊芙。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그 고통으로부터 널 이해할 수 있는 사람은 같은 세월을 견딘 나 밖에 없어.","JPN":"その苦しみとお前を理解できるのは、同じ歳月を耐えてきた私しかいないわ。","ENG":"The only person who can understand that pain is me, who has also endured an eternity.","TWN":"能夠理解你痛苦的人，就只有忍受了相同歲月的我而已。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"백 번, 천 번 양보해서…… 그 망할 버넷이 이곳에 도착했다 하더라도.","JPN":"百歩譲って……あのクソバーネットがここに辿り着けたとしても。","ENG":"Let's say that by some miracle... that damned bastard Burnett does arrive.","TWN":"就算我百般讓步……那個該死的伯內特能到達這裡。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"지금 네 꼴을 보고도 그 역겨운 자식이 널 구하려 들까?","JPN":"今のその醜い姿を見て、あいつがお前を救う気になると思う？","ENG":"Do you really think that the disgusting bastard would still save you after seeing what you are now?","TWN":"但看到你現在這個樣子後，你覺得那噁心的傢伙還會救你嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"네 몸에서 자라난 그 흉측한 파편이 앞으로 수없이 많은 사람을 죽일지도 모르는데?","JPN":"お前の体から生えてきたあの身の毛もよだつ破片が、これから大勢の人を殺してしまうかもしれないのに？","ENG":"He knows well enough that those hideous Fragments growing from your body could end countless lives.","TWN":"你身上長出的那些醜陋碎片，也許以後會害死無數人喔？"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그, 그건…….","JPN":"そ、それは……","ENG":"Th-that's...","TWN":"我，我……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"녀석의 본질은 사냥개야.","JPN":"やつの本質は猟犬よ。","ENG":"He is nothing but a hound. It's in his nature.","TWN":"那傢伙的本質是獵犬。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"겉만 번지르르하지, 대의를 위해서라면 누구든 기쁘게 죽일 수 있는 살인마라고.","JPN":"見た目はいいけど、大儀のためなら誰でも簡単に殺せる殺人鬼なのよ。","ENG":"He might look gentle on the outside, but he is a ruthless murderer who would gladly kill anyone for the greater good.","TWN":"是個虛有其表，為了大局不惜殺人的殺人魔。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그래도…… 기다릴 거예요.","JPN":"それでも……待ちます。","ENG":"But still... I'm going to wait.","TWN":"即使如此……我也會等他。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"버려진 이 세계에서 내가 이 파편을 붙잡고 있는 한…… 아무도 불행해지지 않을 테니까.","JPN":"捨てられたこの世界で、私がこの破片を捉まえている限り……誰も不幸にならないはずだから。","ENG":"Because, as long as I hold this Fragment in this ruined world... no one will be unhappy.","TWN":"在這個被遺棄的世界裡，只要我抓住這個碎片……就不會有人變得不幸。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"전 참는 것 만큼은 자신 있으니까요.","JPN":"私、耐えることなら自信ありますので。","ENG":"If there's one thing I'm good at, it's enduring.","TWN":"因為我對忍耐是很有信心的。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"요원님이 오지 않는다고 해도, 참을 거예요. 언제까지나!","JPN":"バーネット様が来てくれなくても、耐え抜きます。いつまでも……！","ENG":"Even if he doesn't come, I'm going to endure it. Forever!","TWN":"就算他不來，我也會忍耐，一直忍下去！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"뭐, 좋아. 계속 그렇게 고집부리라고.","JPN":"まあ、いいわ。意地を張るのは自由よ。","ENG":"Well, all right. Keep being stubborn like that.","TWN":"好吧，那你就這麼一直固執下去吧。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"어차피 네 몸은 의식을 통해 빼앗으면 되니까.","JPN":"お前の体なんか、儀式で奪えばいいもの。","ENG":"I'll just take away your body through my ritual, then.","TWN":"反正透過儀式奪走你的身體就好。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"의식……?","JPN":"儀式……？","ENG":"Ritual...?","TWN":"儀式……？"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그래. 난 죽기전에 필사적으로 영지에 방문했던 고고학부장에 내 생존을 알렸어.","JPN":"ええ。私は死ぬ前、領地を訪ねてきた考古学部長に私の生存を知らせたのよ。","ENG":"Yes. Before I died, I desperately informed my survival to the Dean of Archeology who visited the estate.","TWN":"沒錯，我死前向造訪領地的考古學教授傳達了我的存在。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그자에게 통찰이 있다면, 언젠가 학회원들을 이끌고 이곳에 다다르겠지.","JPN":"あの者が察したら、いつか学会員たちを引き連れてここに来るはずだわ。","ENG":"If he has any insight, he'll bring the members of the Society here someday.","TWN":"他若是有遠見卓識，總有一天會帶領學會成員到達這裡的。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"알겠어? 그럼, 네 고집도 거기까지야.","JPN":"いいわね？　その日が来れば、お前は終わりよ。","ENG":"Do you understand? Your stubbornness will all be for nothing.","TWN":"明白了嗎？而你的固執也就只能到那為止了。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};